package org.cycle.graph.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import lombok.extern.slf4j.Slf4j;
import org.cycle.graph.dto.EdgeUpsertRequest;
import org.cycle.graph.dto.GraphCreateRequest;
import org.cycle.graph.dto.GraphDetailResponse;
import org.cycle.graph.dto.GraphUpdateRequest;
import org.cycle.graph.dto.VertexUpsertRequest;
import org.cycle.graph.entity.GraphEdgeEntity;
import org.cycle.graph.entity.GraphInfoEntity;
import org.cycle.graph.entity.GraphVertexEntity;
import org.cycle.graph.entity.Vertex;
import org.cycle.graph.mapper.GraphEdgeMapper;
import org.cycle.graph.mapper.GraphInfoMapper;
import org.cycle.graph.mapper.GraphVertexMapper;
import org.cycle.graph.service.Graph;
import org.cycle.graph.service.GraphCrudService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import javax.annotation.Resource;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.stream.Collectors;

@Slf4j
@Service
public class GraphCrudServiceImpl implements GraphCrudService {

    @Resource
    private GraphInfoMapper graphInfoMapper;

    @Resource
    private GraphVertexMapper graphVertexMapper;

    @Resource
    private GraphEdgeMapper graphEdgeMapper;

    private final Map<String, Graph<String>> graphCache = new ConcurrentHashMap<>();

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphInfoEntity createGraph(GraphCreateRequest request) {
        String name = requireText(request == null ? null : request.getName(), "图名称不能为空");

        GraphInfoEntity entity = new GraphInfoEntity();
        entity.setId(newId());
        entity.setName(name);
        entity.setDescription(trimToNull(request.getDescription()));
        graphInfoMapper.insert(entity);
        graphCache.put(entity.getId(), new InMemoryDirectedGraph<String>());
        return entity;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphInfoEntity updateGraph(String graphId, GraphUpdateRequest request) {
        GraphInfoEntity existed = getRequiredGraph(graphId);
        if (request == null) {
            return existed;
        }

        boolean changed = false;
        String name = trimToNull(request.getName());
        if (name != null) {
            existed.setName(name);
            changed = true;
        }

        if (request.getDescription() != null) {
            existed.setDescription(trimToNull(request.getDescription()));
            changed = true;
        }

        if (changed) {
            graphInfoMapper.updateById(existed);
        }
        return existed;
    }

    @Override
    public GraphDetailResponse getGraphDetail(String graphId) {
        GraphInfoEntity graph = getRequiredGraph(graphId);
        List<GraphVertexEntity> vertices = listVertices(graphId);
        List<GraphEdgeEntity> edges = listEdges(graphId);

        Graph<String> inMemoryGraph = loadGraph(graphId);
        List<String> inMemoryVertices = inMemoryGraph.getVertices().stream()
                .map(Vertex::getValue)
                .collect(Collectors.toList());

        GraphDetailResponse response = new GraphDetailResponse();
        response.setGraph(graph);
        response.setVertices(vertices);
        response.setEdges(edges);
        response.setInMemoryVertices(inMemoryVertices);
        return response;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteGraph(String graphId) {
        getRequiredGraph(graphId);

        graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>().eq("graph_id", graphId));
        graphVertexMapper.delete(new QueryWrapper<GraphVertexEntity>().eq("graph_id", graphId));
        int affected = graphInfoMapper.deleteById(graphId);
        graphCache.remove(graphId);
        return affected > 0;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphVertexEntity createVertex(String graphId, VertexUpsertRequest request) {
        getRequiredGraph(graphId);
        String vertexValue = requireText(request == null ? null : request.getVertexValue(), "顶点值不能为空");

        GraphVertexEntity duplicated = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("vertex_value", vertexValue));
        if (duplicated != null) {
            throw new IllegalArgumentException("顶点值已存在: " + vertexValue);
        }

        GraphVertexEntity vertex = new GraphVertexEntity();
        vertex.setId(newId());
        vertex.setGraphId(graphId);
        vertex.setVertexValue(vertexValue);
        graphVertexMapper.insert(vertex);

        rebuildGraph(graphId);
        return vertex;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphVertexEntity updateVertex(String graphId, String vertexId, VertexUpsertRequest request) {
        getRequiredGraph(graphId);
        String vertexValue = requireText(request == null ? null : request.getVertexValue(), "顶点值不能为空");

        GraphVertexEntity vertex = getRequiredVertex(graphId, vertexId);
        GraphVertexEntity duplicated = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("vertex_value", vertexValue)
                .ne("id", vertexId));
        if (duplicated != null) {
            throw new IllegalArgumentException("顶点值已存在: " + vertexValue);
        }

        vertex.setVertexValue(vertexValue);
        graphVertexMapper.updateById(vertex);
        rebuildGraph(graphId);
        return vertex;
    }

    @Override
    public List<GraphVertexEntity> listVertices(String graphId) {
        getRequiredGraph(graphId);
        return graphVertexMapper.selectList(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .orderByAsc("created_at"));
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteVertex(String graphId, String vertexId) {
        getRequiredGraph(graphId);
        getRequiredVertex(graphId, vertexId);

        graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .and(wrapper -> wrapper.eq("from_vertex_id", vertexId).or().eq("to_vertex_id", vertexId)));

        int affected = graphVertexMapper.delete(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("id", vertexId));

        rebuildGraph(graphId);
        return affected > 0;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphEdgeEntity createEdge(String graphId, EdgeUpsertRequest request) {
        getRequiredGraph(graphId);
        String fromVertexId = requireText(request == null ? null : request.getFromVertexId(), "起点顶点ID不能为空");
        String toVertexId = requireText(request == null ? null : request.getToVertexId(), "终点顶点ID不能为空");
        Double weight = request != null && request.getWeight() != null ? request.getWeight() : 1.0D;

        getRequiredVertex(graphId, fromVertexId);
        getRequiredVertex(graphId, toVertexId);

        GraphEdgeEntity existed = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("from_vertex_id", fromVertexId)
                .eq("to_vertex_id", toVertexId));
        if (existed != null) {
            throw new IllegalArgumentException("边已存在");
        }

        GraphEdgeEntity edge = new GraphEdgeEntity();
        edge.setId(newId());
        edge.setGraphId(graphId);
        edge.setFromVertexId(fromVertexId);
        edge.setToVertexId(toVertexId);
        edge.setWeight(weight);
        graphEdgeMapper.insert(edge);

        rebuildGraph(graphId);
        return edge;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphEdgeEntity updateEdge(String graphId, String edgeId, EdgeUpsertRequest request) {
        getRequiredGraph(graphId);
        GraphEdgeEntity edge = getRequiredEdge(graphId, edgeId);
        if (request == null) {
            return edge;
        }

        String fromVertexId = trimToNull(request.getFromVertexId());
        String toVertexId = trimToNull(request.getToVertexId());
        Double weight = request.getWeight();

        if (fromVertexId != null) {
            getRequiredVertex(graphId, fromVertexId);
            edge.setFromVertexId(fromVertexId);
        }
        if (toVertexId != null) {
            getRequiredVertex(graphId, toVertexId);
            edge.setToVertexId(toVertexId);
        }
        if (weight != null) {
            edge.setWeight(weight);
        }

        GraphEdgeEntity duplicated = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("from_vertex_id", edge.getFromVertexId())
                .eq("to_vertex_id", edge.getToVertexId())
                .ne("id", edgeId));
        if (duplicated != null) {
            throw new IllegalArgumentException("边已存在");
        }

        graphEdgeMapper.updateById(edge);
        rebuildGraph(graphId);
        return edge;
    }

    @Override
    public List<GraphEdgeEntity> listEdges(String graphId) {
        getRequiredGraph(graphId);
        return graphEdgeMapper.selectList(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .orderByAsc("created_at"));
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteEdge(String graphId, String edgeId) {
        getRequiredGraph(graphId);
        getRequiredEdge(graphId, edgeId);

        int affected = graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("id", edgeId));

        rebuildGraph(graphId);
        return affected > 0;
    }

    private Graph<String> loadGraph(String graphId) {
        return graphCache.computeIfAbsent(graphId, this::buildGraphFromStorage);
    }

    private void rebuildGraph(String graphId) {
        graphCache.put(graphId, buildGraphFromStorage(graphId));
    }

    private Graph<String> buildGraphFromStorage(String graphId) {
        List<GraphVertexEntity> vertices = graphVertexMapper.selectList(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId));
        List<GraphEdgeEntity> edges = graphEdgeMapper.selectList(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId));

        Map<String, String> vertexIdValueMap = vertices.stream().collect(Collectors.toMap(
                GraphVertexEntity::getId,
                GraphVertexEntity::getVertexValue,
                (left, right) -> left
        ));

        InMemoryDirectedGraph<String> graph = new InMemoryDirectedGraph<>();
        for (GraphVertexEntity vertex : vertices) {
            graph.addVertex(vertex.getVertexValue());
        }

        for (GraphEdgeEntity edge : edges) {
            String from = vertexIdValueMap.get(edge.getFromVertexId());
            String to = vertexIdValueMap.get(edge.getToVertexId());
            if (from == null || to == null) {
                log.warn("边存在脏数据，已忽略，edgeId={}", edge.getId());
                continue;
            }
            graph.addEdge(from, to, edge.getWeight() == null ? 1.0D : edge.getWeight());
        }
        return graph;
    }

    private GraphInfoEntity getRequiredGraph(String graphId) {
        String normalized = requireText(graphId, "图ID不能为空");
        GraphInfoEntity graph = graphInfoMapper.selectById(normalized);
        if (graph == null) {
            throw new IllegalArgumentException("图不存在: " + normalized);
        }
        return graph;
    }

    private GraphVertexEntity getRequiredVertex(String graphId, String vertexId) {
        String normalized = requireText(vertexId, "顶点ID不能为空");
        GraphVertexEntity vertex = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("id", normalized));
        if (vertex == null) {
            throw new IllegalArgumentException("顶点不存在: " + normalized);
        }
        return vertex;
    }

    private GraphEdgeEntity getRequiredEdge(String graphId, String edgeId) {
        String normalized = requireText(edgeId, "边ID不能为空");
        GraphEdgeEntity edge = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("id", normalized));
        if (edge == null) {
            throw new IllegalArgumentException("边不存在: " + normalized);
        }
        return edge;
    }

    private String requireText(String value, String message) {
        String normalized = trimToNull(value);
        if (normalized == null) {
            throw new IllegalArgumentException(message);
        }
        return normalized;
    }

    private String trimToNull(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private String newId() {
        return UUID.randomUUID().toString().replace("-", "");
    }
}

package org.cycle.graph.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import lombok.extern.slf4j.Slf4j;
import org.cycle.graph.dto.EdgeUpsertRequest;
import org.cycle.graph.dto.GraphCreateRequest;
import org.cycle.graph.dto.GraphDetailResponse;
import org.cycle.graph.dto.GraphUpdateRequest;
import org.cycle.graph.dto.VertexUpsertRequest;
import org.cycle.graph.entity.GraphEdgeEntity;
import org.cycle.graph.entity.GraphInfoEntity;
import org.cycle.graph.entity.GraphVertexEntity;
import org.cycle.graph.entity.Vertex;
import org.cycle.graph.mapper.GraphEdgeMapper;
import org.cycle.graph.mapper.GraphInfoMapper;
import org.cycle.graph.mapper.GraphVertexMapper;
import org.cycle.graph.service.Graph;
import org.cycle.graph.service.GraphCrudService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import javax.annotation.Resource;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.stream.Collectors;

@Slf4j
@Service
public class GraphCrudServiceImpl implements GraphCrudService {

    @Resource
    private GraphInfoMapper graphInfoMapper;

    @Resource
    private GraphVertexMapper graphVertexMapper;

    @Resource
    private GraphEdgeMapper graphEdgeMapper;

    private final Map<String, Graph<String>> graphCache = new ConcurrentHashMap<>();

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphInfoEntity createGraph(GraphCreateRequest request) {
        String name = requireText(request == null ? null : request.getName(), "图名称不能为空");

        GraphInfoEntity entity = new GraphInfoEntity();
        entity.setId(newId());
        entity.setName(name);
        entity.setDescription(trimToNull(request == null ? null : request.getDescription()));
        graphInfoMapper.insert(entity);
        graphCache.put(entity.getId(), new InMemoryDirectedGraph<>());
        return entity;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphInfoEntity updateGraph(String graphId, GraphUpdateRequest request) {
        GraphInfoEntity existed = getRequiredGraph(graphId);
        if (request == null) {
            return existed;
        }

        boolean changed = false;
        String name = trimToNull(request.getName());
        if (name != null) {
            existed.setName(name);
            changed = true;
        }

        if (request.getDescription() != null) {
            existed.setDescription(trimToNull(request.getDescription()));
            changed = true;
        }

        if (changed) {
            graphInfoMapper.updateById(existed);
        }
        return existed;
    }

    @Override
    public GraphDetailResponse getGraphDetail(String graphId) {
        GraphInfoEntity graph = getRequiredGraph(graphId);
        List<GraphVertexEntity> vertices = listVertices(graphId);
        List<GraphEdgeEntity> edges = listEdges(graphId);

        Graph<String> inMemoryGraph = loadGraph(graphId);
        List<String> inMemoryVertices = inMemoryGraph.getVertices().stream()
                .map(Vertex::getValue)
                .collect(Collectors.toList());

        GraphDetailResponse response = new GraphDetailResponse();
        response.setGraph(graph);
        response.setVertices(vertices);
        response.setEdges(edges);
        response.setInMemoryVertices(inMemoryVertices);
        return response;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteGraph(String graphId) {
        getRequiredGraph(graphId);

        graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>().eq("graph_id", graphId));
        graphVertexMapper.delete(new QueryWrapper<GraphVertexEntity>().eq("graph_id", graphId));
        int affected = graphInfoMapper.deleteById(graphId);
        graphCache.remove(graphId);
        return affected > 0;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphVertexEntity createVertex(String graphId, VertexUpsertRequest request) {
        getRequiredGraph(graphId);
        String vertexValue = requireText(request == null ? null : request.getVertexValue(), "顶点值不能为空");

        GraphVertexEntity duplicated = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("vertex_value", vertexValue));
        if (duplicated != null) {
            throw new IllegalArgumentException("顶点值已存在: " + vertexValue);
        }

        GraphVertexEntity vertex = new GraphVertexEntity();
        vertex.setId(newId());
        vertex.setGraphId(graphId);
        vertex.setVertexValue(vertexValue);
        graphVertexMapper.insert(vertex);

        rebuildGraph(graphId);
        return vertex;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphVertexEntity updateVertex(String graphId, String vertexId, VertexUpsertRequest request) {
        getRequiredGraph(graphId);
        String vertexValue = requireText(request == null ? null : request.getVertexValue(), "顶点值不能为空");

        GraphVertexEntity vertex = getRequiredVertex(graphId, vertexId);
        GraphVertexEntity duplicated = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("vertex_value", vertexValue)
                .ne("id", vertexId));
        if (duplicated != null) {
            throw new IllegalArgumentException("顶点值已存在: " + vertexValue);
        }

        vertex.setVertexValue(vertexValue);
        graphVertexMapper.updateById(vertex);
        rebuildGraph(graphId);
        return vertex;
    }

    @Override
    public List<GraphVertexEntity> listVertices(String graphId) {
        getRequiredGraph(graphId);
        return graphVertexMapper.selectList(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .orderByAsc("created_at"));
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteVertex(String graphId, String vertexId) {
        getRequiredGraph(graphId);
        getRequiredVertex(graphId, vertexId);

        graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .and(wrapper -> wrapper.eq("from_vertex_id", vertexId).or().eq("to_vertex_id", vertexId)));

        int affected = graphVertexMapper.delete(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("id", vertexId));

        rebuildGraph(graphId);
        return affected > 0;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphEdgeEntity createEdge(String graphId, EdgeUpsertRequest request) {
        getRequiredGraph(graphId);
        String fromVertexId = requireText(request == null ? null : request.getFromVertexId(), "起点顶点ID不能为空");
        String toVertexId = requireText(request == null ? null : request.getToVertexId(), "终点顶点ID不能为空");
        Double weight = request != null && request.getWeight() != null ? request.getWeight() : 1.0D;

        getRequiredVertex(graphId, fromVertexId);
        getRequiredVertex(graphId, toVertexId);

        GraphEdgeEntity existed = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("from_vertex_id", fromVertexId)
                .eq("to_vertex_id", toVertexId));
        if (existed != null) {
            throw new IllegalArgumentException("边已存在");
        }

        GraphEdgeEntity edge = new GraphEdgeEntity();
        edge.setId(newId());
        edge.setGraphId(graphId);
        edge.setFromVertexId(fromVertexId);
        edge.setToVertexId(toVertexId);
        edge.setWeight(weight);
        graphEdgeMapper.insert(edge);

        rebuildGraph(graphId);
        return edge;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public GraphEdgeEntity updateEdge(String graphId, String edgeId, EdgeUpsertRequest request) {
        getRequiredGraph(graphId);
        GraphEdgeEntity edge = getRequiredEdge(graphId, edgeId);
        if (request == null) {
            return edge;
        }

        String fromVertexId = trimToNull(request.getFromVertexId());
        String toVertexId = trimToNull(request.getToVertexId());
        Double weight = request.getWeight();

        if (fromVertexId != null) {
            getRequiredVertex(graphId, fromVertexId);
            edge.setFromVertexId(fromVertexId);
        }
        if (toVertexId != null) {
            getRequiredVertex(graphId, toVertexId);
            edge.setToVertexId(toVertexId);
        }
        if (weight != null) {
            edge.setWeight(weight);
        }

        GraphEdgeEntity duplicated = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("from_vertex_id", edge.getFromVertexId())
                .eq("to_vertex_id", edge.getToVertexId())
                .ne("id", edgeId));
        if (duplicated != null) {
            throw new IllegalArgumentException("边已存在");
        }

        graphEdgeMapper.updateById(edge);
        rebuildGraph(graphId);
        return edge;
    }

    @Override
    public List<GraphEdgeEntity> listEdges(String graphId) {
        getRequiredGraph(graphId);
        return graphEdgeMapper.selectList(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .orderByAsc("created_at"));
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public boolean deleteEdge(String graphId, String edgeId) {
        getRequiredGraph(graphId);
        getRequiredEdge(graphId, edgeId);

        int affected = graphEdgeMapper.delete(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("id", edgeId));

        rebuildGraph(graphId);
        return affected > 0;
    }

    private Graph<String> loadGraph(String graphId) {
        return graphCache.computeIfAbsent(graphId, this::buildGraphFromStorage);
    }

    private void rebuildGraph(String graphId) {
        graphCache.put(graphId, buildGraphFromStorage(graphId));
    }

    private Graph<String> buildGraphFromStorage(String graphId) {
        List<GraphVertexEntity> vertices = graphVertexMapper.selectList(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId));
        List<GraphEdgeEntity> edges = graphEdgeMapper.selectList(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId));

        Map<String, String> vertexIdValueMap = vertices.stream().collect(Collectors.toMap(
                GraphVertexEntity::getId,
                GraphVertexEntity::getVertexValue,
                (left, right) -> left
        ));

        InMemoryDirectedGraph<String> graph = new InMemoryDirectedGraph<>();
        for (GraphVertexEntity vertex : vertices) {
            graph.addVertex(vertex.getVertexValue());
        }

        for (GraphEdgeEntity edge : edges) {
            String from = vertexIdValueMap.get(edge.getFromVertexId());
            String to = vertexIdValueMap.get(edge.getToVertexId());
            if (from == null || to == null) {
                log.warn("边存在脏数据，已忽略，edgeId={}", edge.getId());
                continue;
            }
            graph.addEdge(from, to, edge.getWeight() == null ? 1.0D : edge.getWeight());
        }
        return graph;
    }

    private GraphInfoEntity getRequiredGraph(String graphId) {
        String normalized = requireText(graphId, "图ID不能为空");
        GraphInfoEntity graph = graphInfoMapper.selectById(normalized);
        if (graph == null) {
            throw new IllegalArgumentException("图不存在: " + normalized);
        }
        return graph;
    }

    private GraphVertexEntity getRequiredVertex(String graphId, String vertexId) {
        String normalized = requireText(vertexId, "顶点ID不能为空");
        GraphVertexEntity vertex = graphVertexMapper.selectOne(new QueryWrapper<GraphVertexEntity>()
                .eq("graph_id", graphId)
                .eq("id", normalized));
        if (vertex == null) {
            throw new IllegalArgumentException("顶点不存在: " + normalized);
        }
        return vertex;
    }

    private GraphEdgeEntity getRequiredEdge(String graphId, String edgeId) {
        String normalized = requireText(edgeId, "边ID不能为空");
        GraphEdgeEntity edge = graphEdgeMapper.selectOne(new QueryWrapper<GraphEdgeEntity>()
                .eq("graph_id", graphId)
                .eq("id", normalized));
        if (edge == null) {
            throw new IllegalArgumentException("边不存在: " + normalized);
        }
        return edge;
    }

    private String requireText(String value, String message) {
        String normalized = trimToNull(value);
        if (normalized == null) {
            throw new IllegalArgumentException(message);
        }
        return normalized;
    }

    private String trimToNull(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private String newId() {
        return UUID.randomUUID().toString().replace("-", "");
    }
}

