}

CREATE TABLE WF_PROCESS_DEF ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, CODE VARCHAR(64) NOT NULL, NAME VARCHAR(128) NOT NULL, VERSION_NO INT NOT NULL, STATUS INT DEFAULT 1 NOT NULL, IS_LATEST INT DEFAULT 1 NOT NULL, REMARK VARCHAR(512), CONSTRAINT PK_WF_PROCESS_DEF PRIMARY KEY (ID), CONSTRAINT UK_WF_PROCESS_DEF_CODE_VER UNIQUE (CODE, VERSION_NO) );
CREATE TABLE WF_PROCESS_NODE_DEF ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, DEF_ID VARCHAR(64) NOT NULL, NODE_KEY VARCHAR(64) NOT NULL, NODE_NAME VARCHAR(128) NOT NULL, SORT_NO INT NOT NULL, APPROVAL_MODE VARCHAR(32) NOT NULL, ASSIGNEE_EXPR VARCHAR(512) NOT NULL, CONSTRAINT PK_WF_PROCESS_NODE_DEF PRIMARY KEY (ID) );
CREATE INDEX IDX_WF_NODE_DEF_DEF_SORT ON WF_PROCESS_NODE_DEF (DEF_ID, SORT_NO);
CREATE TABLE WF_PROCESS_INST ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, DEF_ID VARCHAR(64) NOT NULL, DEF_CODE VARCHAR(64) NOT NULL, DEF_VERSION INT NOT NULL, BIZ_TYPE VARCHAR(64) NOT NULL, BIZ_ID VARCHAR(64) NOT NULL, STATE VARCHAR(32) NOT NULL, CURRENT_NODE_KEY VARCHAR(64), STARTER VARCHAR(64) NOT NULL, VARIABLES_JSON CLOB, REVISION INT DEFAULT 0 NOT NULL, CONSTRAINT PK_WF_PROCESS_INST PRIMARY KEY (ID) );
CREATE INDEX IDX_WF_INST_BIZ ON WF_PROCESS_INST (BIZ_TYPE, BIZ_ID); CREATE INDEX IDX_WF_INST_STATE ON WF_PROCESS_INST (STATE);
CREATE TABLE WF_TASK_INST ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, INSTANCE_ID VARCHAR(64) NOT NULL, NODE_KEY VARCHAR(64) NOT NULL, ASSIGNEE VARCHAR(64) NOT NULL, STATE VARCHAR(32) NOT NULL, VOTE_RESULT VARCHAR(32), DELEGATED_FROM VARCHAR(64), COMPLETED_AT TIMESTAMP, REVISION INT DEFAULT 0 NOT NULL, CONSTRAINT PK_WF_TASK_INST PRIMARY KEY (ID) );
CREATE INDEX IDX_WF_TASK_INST_NODE ON WF_TASK_INST (INSTANCE_ID, NODE_KEY); CREATE INDEX IDX_WF_TASK_ASSIGNEE ON WF_TASK_INST (ASSIGNEE, STATE);
CREATE TABLE WF_ACTION_LOG ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, INSTANCE_ID VARCHAR(64) NOT NULL, TASK_ID VARCHAR(64), ACTION_TYPE VARCHAR(32) NOT NULL, OPERATOR VARCHAR(64) NOT NULL, ACTION_COMMENT VARCHAR(1000), SNAPSHOT_JSON CLOB, CONSTRAINT PK_WF_ACTION_LOG PRIMARY KEY (ID) );
CREATE INDEX IDX_WF_ACTION_LOG_INST ON WF_ACTION_LOG (INSTANCE_ID);
CREATE TABLE WF_IDEMPOTENT ( ID VARCHAR(64) NOT NULL, CREATED_BY VARCHAR(64), UPDATED_BY VARCHAR(64), CREATED_AT TIMESTAMP, UPDATED_AT TIMESTAMP, REQUEST_ID VARCHAR(128) NOT NULL, ACTION_TYPE VARCHAR(32) NOT NULL, INSTANCE_ID VARCHAR(64) NOT NULL, RESPONSE_JSON CLOB, CONSTRAINT PK_WF_IDEMPOTENT PRIMARY KEY (ID), CONSTRAINT UK_WF_IDEMPOTENT_REQ UNIQUE (REQUEST_ID, ACTION_TYPE) );
COMMENT ON TABLE WF_PROCESS_DEF IS '流程定义主表（版本化）'; COMMENT ON TABLE WF_PROCESS_NODE_DEF IS '流程节点定义'; COMMENT ON TABLE WF_PROCESS_INST IS '流程实例'; COMMENT ON TABLE WF_TASK_INST IS '任务实例'; COMMENT ON TABLE WF_ACTION_LOG IS '流程动作日志'; COMMENT ON TABLE WF_IDEMPOTENT IS '幂等记录表';

CREATE TABLE WF_PROCESS_DEF (
    ID            VARCHAR(64)   NOT NULL,
    CREATED_BY    VARCHAR(64),
    UPDATED_BY    VARCHAR(64),
    CREATED_AT    TIMESTAMP,
    UPDATED_AT    TIMESTAMP,
    CODE          VARCHAR(64)   NOT NULL,
    NAME          VARCHAR(128)  NOT NULL,
    VERSION_NO    INT           NOT NULL,
    STATUS        INT DEFAULT 1 NOT NULL,
    IS_LATEST     INT DEFAULT 1 NOT NULL,
    REMARK        VARCHAR(512),
    CONSTRAINT PK_WF_PROCESS_DEF PRIMARY KEY (ID),
    CONSTRAINT UK_WF_PROCESS_DEF_CODE_VER UNIQUE (CODE, VERSION_NO)
);

CREATE TABLE WF_PROCESS_NODE_DEF (
    ID              VARCHAR(64)   NOT NULL,
    CREATED_BY      VARCHAR(64),
    UPDATED_BY      VARCHAR(64),
    CREATED_AT      TIMESTAMP,
    UPDATED_AT      TIMESTAMP,
    DEF_ID          VARCHAR(64)   NOT NULL,
    NODE_KEY        VARCHAR(64)   NOT NULL,
    NODE_NAME       VARCHAR(128)  NOT NULL,
    SORT_NO         INT           NOT NULL,
    APPROVAL_MODE   VARCHAR(32)   NOT NULL,
    ASSIGNEE_EXPR   VARCHAR(512)  NOT NULL,
    CONSTRAINT PK_WF_PROCESS_NODE_DEF PRIMARY KEY (ID)
);

CREATE INDEX IDX_WF_NODE_DEF_DEF_SORT ON WF_PROCESS_NODE_DEF (DEF_ID, SORT_NO);

CREATE TABLE WF_PROCESS_INST (
    ID               VARCHAR(64)   NOT NULL,
    CREATED_BY       VARCHAR(64),
    UPDATED_BY       VARCHAR(64),
    CREATED_AT       TIMESTAMP,
    UPDATED_AT       TIMESTAMP,
    DEF_ID           VARCHAR(64)   NOT NULL,
    DEF_CODE         VARCHAR(64)   NOT NULL,
    DEF_VERSION      INT           NOT NULL,
    BIZ_TYPE         VARCHAR(64)   NOT NULL,
    BIZ_ID           VARCHAR(64)   NOT NULL,
    STATE            VARCHAR(32)   NOT NULL,
    CURRENT_NODE_KEY VARCHAR(64),
    STARTER          VARCHAR(64)   NOT NULL,
    VARIABLES_JSON   CLOB,
    REVISION         INT DEFAULT 0 NOT NULL,
    CONSTRAINT PK_WF_PROCESS_INST PRIMARY KEY (ID)
);

CREATE INDEX IDX_WF_INST_BIZ ON WF_PROCESS_INST (BIZ_TYPE, BIZ_ID);
CREATE INDEX IDX_WF_INST_STATE ON WF_PROCESS_INST (STATE);

CREATE TABLE WF_TASK_INST (
    ID               VARCHAR(64)   NOT NULL,
    CREATED_BY       VARCHAR(64),
    UPDATED_BY       VARCHAR(64),
    CREATED_AT       TIMESTAMP,
    UPDATED_AT       TIMESTAMP,
    INSTANCE_ID      VARCHAR(64)   NOT NULL,
    NODE_KEY         VARCHAR(64)   NOT NULL,
    ASSIGNEE         VARCHAR(64)   NOT NULL,
    STATE            VARCHAR(32)   NOT NULL,
    VOTE_RESULT      VARCHAR(32),
    DELEGATED_FROM   VARCHAR(64),
    COMPLETED_AT     TIMESTAMP,
    REVISION         INT DEFAULT 0 NOT NULL,
    CONSTRAINT PK_WF_TASK_INST PRIMARY KEY (ID)
);

CREATE INDEX IDX_WF_TASK_INST_NODE ON WF_TASK_INST (INSTANCE_ID, NODE_KEY);
CREATE INDEX IDX_WF_TASK_ASSIGNEE ON WF_TASK_INST (ASSIGNEE, STATE);

CREATE TABLE WF_ACTION_LOG (
    ID             VARCHAR(64)    NOT NULL,
    CREATED_BY     VARCHAR(64),
    UPDATED_BY     VARCHAR(64),
    CREATED_AT     TIMESTAMP,
    UPDATED_AT     TIMESTAMP,
    INSTANCE_ID    VARCHAR(64)    NOT NULL,
    TASK_ID        VARCHAR(64),
    ACTION_TYPE    VARCHAR(32)    NOT NULL,
    OPERATOR       VARCHAR(64)    NOT NULL,
    ACTION_COMMENT VARCHAR(1000),
    SNAPSHOT_JSON  CLOB,
    CONSTRAINT PK_WF_ACTION_LOG PRIMARY KEY (ID)
);

CREATE INDEX IDX_WF_ACTION_LOG_INST ON WF_ACTION_LOG (INSTANCE_ID);

CREATE TABLE WF_IDEMPOTENT (
    ID             VARCHAR(64)   NOT NULL,
    CREATED_BY     VARCHAR(64),
    UPDATED_BY     VARCHAR(64),
    CREATED_AT     TIMESTAMP,
    UPDATED_AT     TIMESTAMP,
    REQUEST_ID     VARCHAR(128)  NOT NULL,
    ACTION_TYPE    VARCHAR(32)   NOT NULL,
    INSTANCE_ID    VARCHAR(64)   NOT NULL,
    RESPONSE_JSON  CLOB,
    CONSTRAINT PK_WF_IDEMPOTENT PRIMARY KEY (ID),
    CONSTRAINT UK_WF_IDEMPOTENT_REQ UNIQUE (REQUEST_ID, ACTION_TYPE)
);

COMMENT ON TABLE WF_PROCESS_DEF IS '流程定义主表（版本化）';
COMMENT ON COLUMN WF_PROCESS_DEF.ID IS '主键ID';
COMMENT ON COLUMN WF_PROCESS_DEF.CREATED_BY IS '创建人';
COMMENT ON COLUMN WF_PROCESS_DEF.UPDATED_BY IS '更新人';
COMMENT ON COLUMN WF_PROCESS_DEF.CREATED_AT IS '创建时间';
COMMENT ON COLUMN WF_PROCESS_DEF.UPDATED_AT IS '更新时间';
COMMENT ON COLUMN WF_PROCESS_DEF.CODE IS '流程编码（同一流程跨版本共享）';
COMMENT ON COLUMN WF_PROCESS_DEF.NAME IS '流程名称';
COMMENT ON COLUMN WF_PROCESS_DEF.VERSION_NO IS '流程版本号，从1开始递增';
COMMENT ON COLUMN WF_PROCESS_DEF.STATUS IS '定义状态：1-启用，0-停用';
COMMENT ON COLUMN WF_PROCESS_DEF.IS_LATEST IS '是否最新版本：1-是，0-否';
COMMENT ON COLUMN WF_PROCESS_DEF.REMARK IS '定义备注';

COMMENT ON TABLE WF_PROCESS_NODE_DEF IS '流程节点定义';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.ID IS '主键ID';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.CREATED_BY IS '创建人';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.UPDATED_BY IS '更新人';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.CREATED_AT IS '创建时间';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.UPDATED_AT IS '更新时间';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.DEF_ID IS '所属流程定义ID';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.NODE_KEY IS '节点编码（定义内唯一）';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.NODE_NAME IS '节点名称';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.SORT_NO IS '节点顺序号（升序流转）';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.APPROVAL_MODE IS '审批模式：BASIC/OR_SIGN/COUNTER_SIGN';
COMMENT ON COLUMN WF_PROCESS_NODE_DEF.ASSIGNEE_EXPR IS '审批人表达式，当前以逗号分隔账号';

COMMENT ON TABLE WF_PROCESS_INST IS '流程实例';
COMMENT ON COLUMN WF_PROCESS_INST.ID IS '主键ID';
COMMENT ON COLUMN WF_PROCESS_INST.CREATED_BY IS '创建人';
COMMENT ON COLUMN WF_PROCESS_INST.UPDATED_BY IS '更新人';
COMMENT ON COLUMN WF_PROCESS_INST.CREATED_AT IS '创建时间';
COMMENT ON COLUMN WF_PROCESS_INST.UPDATED_AT IS '更新时间';
COMMENT ON COLUMN WF_PROCESS_INST.DEF_ID IS '关联流程定义ID';
COMMENT ON COLUMN WF_PROCESS_INST.DEF_CODE IS '流程编码（冗余便于查询）';
COMMENT ON COLUMN WF_PROCESS_INST.DEF_VERSION IS '流程定义版本号（实例绑定）';
COMMENT ON COLUMN WF_PROCESS_INST.BIZ_TYPE IS '业务类型（引擎不感知具体业务）';
COMMENT ON COLUMN WF_PROCESS_INST.BIZ_ID IS '业务单据ID';
COMMENT ON COLUMN WF_PROCESS_INST.STATE IS '流程状态：DRAFT/RUNNING/COMPLETED/TERMINATED/WITHDRAWN';
