COMMENT ON COLUMN WF_PROCESS_INST.VARIABLES_JSON IS '流程变量JSON';
COMMENT ON COLUMN WF_PROCESS_INST.REVISION IS '乐观锁版本号';

COMMENT ON TABLE WF_TASK_INST IS '任务实例';
COMMENT ON COLUMN WF_TASK_INST.ID IS '主键ID';
COMMENT ON COLUMN WF_TASK_INST.CREATED_BY IS '创建人';
COMMENT ON COLUMN WF_TASK_INST.UPDATED_BY IS '更新人';
COMMENT ON COLUMN WF_TASK_INST.CREATED_AT IS '创建时间';
COMMENT ON COLUMN WF_TASK_INST.UPDATED_AT IS '更新时间';
COMMENT ON COLUMN WF_TASK_INST.INSTANCE_ID IS '所属流程实例ID';
COMMENT ON COLUMN WF_TASK_INST.NODE_KEY IS '所属节点编码';
