COMMENT ON TABLE WF_ACTION_LOG IS '流程动作日志';
COMMENT ON COLUMN WF_ACTION_LOG.ID IS '主键ID';
COMMENT ON COLUMN WF_ACTION_LOG.CREATED_BY IS '创建人';
COMMENT ON COLUMN WF_ACTION_LOG.UPDATED_BY IS '更新人';
COMMENT ON COLUMN WF_ACTION_LOG.CREATED_AT IS '创建时间';
COMMENT ON COLUMN WF_ACTION_LOG.UPDATED_AT IS '更新时间';
COMMENT ON COLUMN WF_ACTION_LOG.INSTANCE_ID IS '流程实例ID';
